@import '../../utils/control-inactive.css';

:host {
  display: inline-block;
}

.pagination {
  display: flex;
  align-items: center;
  gap: var(--dimension-space-025);
  -webkit-user-select: none;
  user-select: none;
}

/* Inactive: `.ds-control-inactive` (25% opacity). */

.button {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: var(--dimension-size-300);
  height: var(--dimension-size-300);
  padding: 0 var(--dimension-space-050);
  background: none;
  border: none;
  border-radius: var(--dimension-radius-075);
  cursor: pointer;
  color: var(--color-foreground-secondary);
  transition: background-color var(--effect-motion-short-2), color var(--effect-motion-short-2);
}

.button:hover:not(:disabled) {
  background-color: var(--color-interaction-hover);
  color: var(--color-foreground-primary);
}

.button:active:not(:disabled) {
  background-color: var(--color-interaction-pressed);
}

.button:disabled {
  cursor: not-allowed;
  opacity: 0.35;
}

.button:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-stroke-width-015);
}

.button--active {
  background-color: var(--color-interaction-hover);
  color: var(--color-foreground-primary);
}

.button--nav {
  font-size: var(--typography-fontsize-md);
  line-height: var(--typography-lineheight-md);
}

.ellipsis {
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: var(--dimension-size-300);
  height: var(--dimension-size-300);
}

import { Component, Prop, Event, EventEmitter, h, Host } from '@stencil/core';

function buildRange(start: number, end: number): (number | 'ellipsis')[] {
  const items: (number | 'ellipsis')[] = [];
  for (let i = start; i <= end; i++) items.push(i);
  return items;
}

function buildPages(page: number, totalPages: number, siblings: number): (number | 'ellipsis')[] {
  const totalSlots = siblings * 2 + 5;
  if (totalPages <= totalSlots) return buildRange(1, totalPages);

  const leftSibling = Math.max(page - siblings, 2);
  const rightSibling = Math.min(page + siblings, totalPages - 1);
  const showLeft = leftSibling > 2;
  const showRight = rightSibling < totalPages - 1;

  if (!showLeft && showRight) return [...buildRange(1, siblings * 2 + 3), 'ellipsis', totalPages];
  if (showLeft && !showRight) return [1, 'ellipsis', ...buildRange(totalPages - (siblings * 2 + 2), totalPages)];
  return [1, 'ellipsis', ...buildRange(leftSibling, rightSibling), 'ellipsis', totalPages];
}

@Component({
  tag: 'ds-pagination',
  styleUrl: 'Pagination.css',
  scoped: true,
})
export class Pagination {
  @Prop({ mutable: true }) page: number = 1;
  @Prop() totalPages: number = 1;
  @Prop() siblingCount: number = 1;
  @Prop() isInactive: boolean = false;
  @Prop() paginationLabel: string = 'Pagination';
  @Prop() previousPageLabel: string = 'Previous page';
  @Prop() nextPageLabel: string = 'Next page';

  @Event() dsPageChange!: EventEmitter<number>;

  private go(p: number) {
    if (this.isInactive) return;
    this.page = p;
    this.dsPageChange.emit(p);
  }

  render() {
    if (this.totalPages <= 1) return <Host style={{ display: 'none' }} />;

    const pages = buildPages(this.page, this.totalPages, this.siblingCount);

    return (
      <Host>
        <nav
          class={{ pagination: true, 'ds-control-inactive': this.isInactive }}
          aria-label={this.paginationLabel}
        >
          <button
            type="button"
            class="button button--nav"
            disabled={this.page <= 1 || this.isInactive}
            onClick={() => this.go(this.page - 1)}
            aria-label={this.previousPageLabel}
          >
            &#x2039;
          </button>

          {pages.map((item, i) =>
            item === 'ellipsis' ? (
              <ds-text key={`e${i}`} class="ellipsis" as="span" variant="text-body-small" color="tertiary">
                …
              </ds-text>
            ) : (
              <button
                key={item}
                type="button"
                class={{ button: true, 'button--active': item === this.page }}
                onClick={() => this.go(item)}
                aria-current={item === this.page ? 'page' : undefined}
                disabled={this.isInactive}
              >
                <ds-text as="span" variant="text-body-small" emphasis={item === this.page}>
                  {item}
                </ds-text>
              </button>
            )
          )}

          <button
            type="button"
            class="button button--nav"
            disabled={this.page >= this.totalPages || this.isInactive}
            onClick={() => this.go(this.page + 1)}
            aria-label={this.nextPageLabel}
          >
            &#x203A;
          </button>
        </nav>
      </Host>
    );
  }
}
